(function($){'use strict';function getCurrentSelections($form){var selections={};$form.find('.wse-swatch-wrap').each(function(){var attribute=$(this).data('attribute');var $selected=$(this).find('.wse-swatch.selected');selections['attribute_'+attribute]=$selected.length?String($selected.data('value')):'';});return selections;}
function isValueAvailable(variations,currentSelections,attrKey,swatchValue){return variations.some(function(variation){if(!variation.is_in_stock&&!variation.is_purchasable){return false;}
for(var key in currentSelections){if(key===attrKey){continue;}
var selectedVal=currentSelections[key];if(!selectedVal){continue;}
var variationVal=variation.attributes[key]||'';if(variationVal!==''&&variationVal!==selectedVal){return false;}}
var ownVariationVal=variation.attributes[attrKey]||'';return ownVariationVal===''||ownVariationVal===swatchValue;});}
function updateAvailability($form){var variations=$form.data('product_variations');if(!variations||variations===false){return;}
var currentSelections=getCurrentSelections($form);$form.find('.wse-swatch-wrap').each(function(){var attribute=$(this).data('attribute');var attrKey='attribute_'+attribute;$(this).find('.wse-swatch').each(function(){var $swatch=$(this);var swatchValue=String($swatch.data('value'));if($swatch.hasClass('disabled')){return;}
var available=isValueAvailable(variations,currentSelections,attrKey,swatchValue);if(available){$swatch.removeClass('filtered-out').attr('aria-disabled','false');}else{$swatch.addClass('filtered-out').attr('aria-disabled','true');}});});}
function clearFilteredOut($form){$form.find('.wse-swatch.filtered-out').removeClass('filtered-out').attr('aria-disabled','false');}
$(document.body).on('wse:swatchSelected',function(e,data){if(data&&data.$form){updateAvailability(data.$form);}});$(document.body).on('wse:swatchDeselected',function(e,data){if(data&&data.$form){updateAvailability(data.$form);}});$(document.body).on('wse:swatchReset',function(e,data){if(data&&data.$form){clearFilteredOut(data.$form);}});$(document).on('woocommerce_variation_has_changed','form.variations_form',function(){updateAvailability($(this));});$(document.body).on('wse:reinit post-load elementor/popup/show',function(){$('form.variations_form').each(function(){updateAvailability($(this));});});})(jQuery);